/**
 * Translates a protective action string.
 * Falls back to the original Polish text if no translation found.
 */
export function translateAction(action: string | undefined | null, lang: Lang): string {
  if (!action) return ''
  if (lang === 'pl') return action
  return actionsI18n[action]?.[lang] || action
}